  "SCORE-UPD": {
   "name": "SCORE-UPD",
   "file": "verbs.zil",
   "line": 2662,
   "endLine": 2672,
   "source": "<ROUTINE SCORE-UPD (NUM)\n\t #DECL ((NUM) FIX)\n\t <SETG SCORE <+ ,SCORE .NUM>>\n\t <TELL \"(\">\n\t <COND (<G? 0 .NUM> <TELL \"Oh no! \">)>\n\t <TELL \"Your score just went \">\n\t <COND (<L? 0 .NUM> <TELL \"up\">)\n\t       (T <SET NUM <- 0 .NUM>> <TELL \"down\">)>\n\t <TELL \" by \" N .NUM \" point\">\n\t <COND (<NOT <1? .NUM>> <TELL \"s\">)>\n\t <TELL \"!)\" CR>>"
  },
  "SCORE-OBJ": {
   "name": "SCORE-OBJ",
   "file": "verbs.zil",
   "line": 2674,
   "endLine": 2679,
   "source": "<ROUTINE SCORE-OBJ (OBJ \"AUX\" TEMP)\n\t #DECL ((OBJ) OBJECT (TEMP) FIX)\n\t <COND (<SET TEMP <GETP .OBJ ,P?VALUE>>\n\t\t<COND (<G? .TEMP 0>\n\t\t       <SCORE-UPD .TEMP>\n\t\t       <PUTP .OBJ ,P?VALUE 0>)>)>>"
  },
  "V-SCORE": {
   "name": "V-SCORE",
   "file": "verbs.zil",
   "line": 2681,
   "endLine": 2691,
   "source": "<ROUTINE V-SCORE ()\n\t <TELL \"Your score is \" N ,SCORE \" point\">\n\t <COND (<NOT <1? ,SCORE>> <TELL \"s\">)>\n\t <TELL \" out of 100, in \" N ,MOVES \" turn\">\n\t <COND (<1? ,MOVES> <TELL \".\">) (ELSE <TELL \"s.\">)>\n\t <CRLF>\n\t <TELL \"This score gives you the rank of a \"\n\t       <COND (<G? 0 ,SCORE> <GET ,RANKS 0>)\n\t\t     (T <GET ,RANKS </ ,SCORE 20>>)>\n\t       \" adventurer.\" CR>\n\t ,SCORE>"
  },
  "FINISH": {
   "name": "FINISH",
   "file": "verbs.zil",
   "line": 2695,
   "endLine": 2723,
   "source": "<ROUTINE FINISH (\"OPTIONAL\" (REPEATING <>) VAL)\n\t <COND (,DEBUG <RTRUE>)>\n\t <CRLF>\n\t <CRLF>\n\t <COND (<NOT .REPEATING>\n\t\t<V-SCORE>\n\t\t<CRLF>)>\n\t <TELL\n\"Would you like to:|\n   RESTORE your place from where you saved it,|\n   RESTART the story from the beginning, or|\n   QUIT for now?|\n\">\n\t<REPEAT ()\n\t <TELL \">\">\n\t <READ ,P-INBUF ,P-LEXV>\n\t <SET VAL <GET ,P-LEXV ,P-LEXSTART>>\n\t <COND (<NOT <0? .VAL>>\n\t\t<SET VAL <WT? .VAL ,PS?VERB ,P1?VERB>>\n\t\t<COND (<EQUAL? .VAL ,ACT?RESTART>\n\t\t       <RESTART>\n\t\t       ;<TELL ,FAILED CR>\n\t\t       <FINISH T>)\n\t\t      (<EQUAL? .VAL ,ACT?RESTORE>\n\t\t       <COND (<V-RESTORE> <RETURN>)>\n\t\t       <FINISH T>)\n\t\t      (<EQUAL? .VAL ,ACT?QUIT>\n\t\t       <QUIT>)>)>\n\t <TELL \"(Type RESTORE, RESTART, or QUIT.) \">>>"
  },
